function IntroVideoBlock({ name }: { name: string }) {
  // const videoShown = localStorage.getItem('video_shown') === 'true'
  const { data, isLoading } = useQuery({
    queryKey: ["intro_video"],
    queryFn: () => {
      return handleIntroductionVideo(name);
    },
  });
  const [showVideoModal, setShowVideoModal] = useState(false);

  if (isLoading) {
    return (
      <div className="py-4 relative w-[328px] shrink-0 max-w-[]">
        <Star06 className="absolute top-5 left-10 rotate-12" size={16} />
        <Star06 className="absolute top-1 right-8 -rotate-12" size={28} />
        <div className="rounded-[16px] bg-gradient-to-tr p-4 from-[rgba(244,144,98,1)] to-[rgba(253,55,31,1)]">
          <div className="text-center text-[14px] leading-[20px] font-medium">
            Ваше персональное приветствие
          </div>
          <Button
            color="secondary"
            size="lg"
            className="w-full mt-3"
            iconLeading={
              <Loading01
                size={20}
                className="text-fg-quaternary animate-spin"
              />
            }
          >
            Ваше видео готовится...
          </Button>
        </div>
      </div>
    );
  }

  if (!data) return null;

  return (
    <>
      <AnimatePresence>
        {showVideoModal && (
          <VideoModal
            url={data.video_url}
            thumbnail={data.thumbnail_url}
            onClose={() => {
              setShowVideoModal(false);
              localStorage.setItem("video_shown", "true");
            }}
          />
        )}
      </AnimatePresence>
      <div className="py-4 relative w-[328px] shrink-0">
        <Star06 className="absolute top-5 left-10 rotate-12" size={16} />
        <Star06 className="absolute top-1 right-8 -rotate-12" size={28} />
        <div className="rounded-[16px] h-full flex flex-col items-center justify-center bg-gradient-to-tr p-4 from-[rgba(244,144,98,1)] to-[rgba(253,55,31,1)]">
          <div className="text-center text-[14px] leading-[20px] font-medium">
            Ваше персональное приветствие
          </div>
          <Button
            onClick={() => {
              setShowVideoModal(true);
            }}
            color="secondary"
            size="lg"
            className="w-full mt-3"
            iconLeading={
              <PlaySquare size={20} className="text-fg-quaternary" />
            }
          >
            Посмотреть
          </Button>
        </div>
      </div>
    </>
  );
}

