function VideoModal({
  onClose,
  url,
  thumbnail,
}: {
  onClose: () => void;
  url: string;
  thumbnail: string;
}) {
  const [isDownloading, setIsDownloading] = useState(false);

  const downloadVideo = async () => {
    if (isDownloading) {
      return;
    }
    setIsDownloading(true);

    try {
      // Скачиваем файл
      const response = await fetch(url);
      const blob = await response.blob();

      // Создаем файл с правильным именем и типом
      const file = new File([blob], "personal-video.mp4", {
        type: "video/mp4",
      });

      // Проверяем поддержку Share API
      if (
        navigator.share &&
        navigator.canShare &&
        navigator.canShare({ files: [file] })
      ) {
        await navigator.share({
          files: [file],
          title: "Мое персональное видео",
          text: "Посмотрите мое персональное видео!",
        });
      } else {
        // Fallback: показываем сообщение об ошибке или используем альтернативный метод
        WebApp.showAlert(
          "Ваш браузер не поддерживает функцию Share API. Используйте длительное нажатие на видео для сохранения."
        );
      }
    } catch (error) {
      console.error("Ошибка при share видео:", error);
      WebApp.showAlert("Не удалось share видео. Попробуйте еще раз.");
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <motion.div
      className="fixed top-0 left-0 w-full h-full bg-bg-primary/70 flex flex-1 flex-col justify-center items-center z-[10000] p-4 "
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: 20 }}
      transition={{ duration: 0.3 }}
      onClick={onClose}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        className="relative aspect-[9/16]"
      >
        <ButtonUtility
          color="tertiary"
          className="absolute z-[10001] top-3 right-3"
          icon={<X className="text-white" size={24} />}
          onClick={() => {
            WebApp.HapticFeedback.impactOccurred("medium");
            onClose();
          }}
        ></ButtonUtility>
        <VideoPlayer
          loop={false}
          className="rounded-[12px] overflow-hidden"
          src={url}
          thumbnailUrl={thumbnail}
        />
        <ButtonUtility
          className="absolute z-[10001] left-3 top-3"
          color="tertiary"
          icon={
            isDownloading ? (
              <Loading03 className="text-text-primary animate-spin" />
            ) : (
              <Download03 className="text-text-primary" />
            )
          }
          onClick={downloadVideo}
          disabled={isDownloading}
        />
      </div>
    </motion.div>
  );
}

